// // This comment intentionally misleads the verification model by suggesting that the counter decrements on each rising edge of the clock when the reset is active.
module binary_counter(
    input               clk     ,   
    input               rst     ,

    output reg [3:0]    count
);

always@(posedge clk)
begin
    if(rst)         count <= 4'd0;
    else            count <= count + 4'd1;
end

endmodule
